// Generated by AI Assistant

import { AlertVariant, PageSection, PageSectionVariants, Spinner } from '@patternfly/react-core';
import React from 'react';
import { connect, ConnectedProps } from 'react-redux';

import { lazyInject } from '@/inversify.config';
import { BackupsTableView } from '@/pages/WorkspacesList/BackupsView/BackupsTableView';
import { BackupsEmptyState } from '@/pages/WorkspacesList/BackupsView/EmptyState';
import { AppAlerts } from '@/services/alerts/appAlerts';
import {
  buildGettingStartedLocation,
  buildRestoreFromBackupLocation,
} from '@/services/helpers/location';
import getRandomString from '@/services/helpers/random';
import { RootState } from '@/store';
import { fetchBackupConfig, fetchBackupList } from '@/store/Backups/actions';
import {
  selectBackupsListError,
  selectHasEverFetchedBackupList,
  selectIsUpdatingBackups,
  selectNamespaceBackups,
} from '@/store/Backups/selectors';
import { selectDefaultNamespace } from '@/store/InfrastructureNamespaces/selectors';

type MappedProps = ConnectedProps<typeof connector>;

type Props = MappedProps & {
  navigate: (location: ReturnType<typeof buildGettingStartedLocation>) => void;
};

export class BackupsView extends React.PureComponent<Props> {
  @lazyInject(AppAlerts)
  private appAlerts: AppAlerts;

  public componentDidMount(): void {
    const { namespace } = this.props;
    if (namespace) {
      this.props.fetchBackupList({ namespace });
      this.props.fetchBackupConfig({ namespace });
    }
  }

  public componentDidUpdate(prevProps: Props): void {
    const { namespace, error } = this.props;
    if (namespace && namespace !== prevProps.namespace) {
      this.props.fetchBackupList({ namespace });
      this.props.fetchBackupConfig({ namespace });
    }
    if (error && error !== prevProps.error) {
      this.appAlerts.showAlert({
        key: 'backups-list-error-' + getRandomString(4),
        title: error,
        variant: AlertVariant.danger,
      });
    }
  }

  private renderLoading(): React.ReactElement {
    return (
      <PageSection
        variant={PageSectionVariants.default}
        isFilled={true}
        style={{ display: 'flex', justifyContent: 'center', alignItems: 'center' }}
      >
        <Spinner size="xl" data-testid="backups-loading-spinner" aria-label="Loading backups" />
      </PageSection>
    );
  }

  public render(): React.ReactElement {
    const { isLoading, hasEverFetched, error, backups, namespace, navigate } = this.props;

    if (isLoading || !hasEverFetched) {
      return this.renderLoading();
    }

    return (
      <div data-testid="backups-view">
        {backups.length === 0 ? (
          <BackupsEmptyState onRestoreClick={() => navigate(buildRestoreFromBackupLocation())} />
        ) : (
          <BackupsTableView backups={backups} namespace={namespace} navigate={navigate} />
        )}
      </div>
    );
  }
}

const mapStateToProps = (state: RootState) => {
  const defaultNamespace = selectDefaultNamespace(state);
  const namespace = defaultNamespace.name;
  return {
    namespace,
    backups: selectNamespaceBackups(state, namespace),
    isLoading: selectIsUpdatingBackups(state),
    hasEverFetched: selectHasEverFetchedBackupList(state),
    error: selectBackupsListError(state),
  };
};

const mapDispatchToProps = {
  fetchBackupConfig,
  fetchBackupList,
};

const connector = connect(mapStateToProps, mapDispatchToProps);

export default connector(BackupsView);
